const header = document.getElementById("header"),
  backToTop = document.getElementById("backToTop");
window.addEventListener("scroll", () => {
  (header && header.classList.toggle("scrolled", window.scrollY > 20),
    backToTop && backToTop.classList.toggle("show", window.scrollY > 400));
});
const hamburger = document.getElementById("hamburger"),
  nav = document.getElementById("nav");
(hamburger &&
  nav &&
  (hamburger.addEventListener("click", () => {
    (hamburger.classList.toggle("open"), nav.classList.toggle("open"));
  }),
  document.addEventListener("click", (e) => {
    header &&
      !header.contains(e.target) &&
      (hamburger.classList.remove("open"), nav.classList.remove("open"));
  })),
  backToTop &&
    backToTop.addEventListener("click", () => {
      window.scrollTo({ top: 0, behavior: "smooth" });
    }),
  document.querySelectorAll('a[href^="#"]').forEach((e) => {
    e.addEventListener("click", (t) => {
      const o = e.getAttribute("href");
      if (!o || "#" === o) return;
      const r = document.querySelector(o);
      if (r) {
        t.preventDefault();
        const e = (header ? header.offsetHeight : 0) + 80;
        window.scrollTo({
          top: r.getBoundingClientRect().top + window.scrollY - e,
          behavior: "smooth",
        });
      }
    });
  }));
const phaseIds = ["phase1", "phase2", "phase3", "phase4"],
  stripItems = document.querySelectorAll(".ps-item");
if (stripItems.length) {
  const e = new IntersectionObserver(
    (e) => {
      e.forEach((e) => {
        if (e.isIntersecting) {
          const t = e.target.id,
            o = phaseIds.indexOf(t);
          -1 !== o &&
            (stripItems.forEach((e) => e.classList.remove("active")),
            stripItems[o].classList.add("active"));
        }
      });
    },
    { rootMargin: "-30% 0px -60% 0px" },
  );
  phaseIds.forEach((t) => {
    const o = document.getElementById(t);
    o && e.observe(o);
  });
}
const revealObs = new IntersectionObserver(
  (e) => {
    e.forEach((e, t) => {
      e.isIntersecting &&
        (setTimeout(() => e.target.classList.add("visible"), 80 * t),
        revealObs.unobserve(e.target));
    });
  },
  { threshold: 0.1 },
);
([
  ".quality-card",
  ".ct-item",
  ".pb-block",
  ".resp-card",
  ".section-header",
].forEach((e) => {
  document.querySelectorAll(e).forEach((e) => {
    (e.classList.add("reveal"), revealObs.observe(e));
  });
}),
  (function () {
    const e = document.getElementById("phParticles");
    if (!e) return;
    const t = document.createElement("canvas"),
      o = t.getContext("2d");
    e.appendChild(t);
    const r = () => {
      ((t.width = e.offsetWidth), (t.height = e.offsetHeight));
    };
    (r(), window.addEventListener("resize", r));
    const a = Array.from({ length: 50 }, () => ({
      x: Math.random() * t.width,
      y: Math.random() * t.height,
      r: 1.5 * Math.random() + 0.4,
      vx: 0.28 * (Math.random() - 0.5),
      vy: 0.28 * (Math.random() - 0.5),
      a: 0.45 * Math.random() + 0.1,
    }));
    !(function e() {
      (o.clearRect(0, 0, t.width, t.height),
        a.forEach((e) => {
          ((e.x += e.vx),
            (e.y += e.vy),
            (e.x < 0 || e.x > t.width) && (e.vx *= -1),
            (e.y < 0 || e.y > t.height) && (e.vy *= -1),
            o.beginPath(),
            o.arc(e.x, e.y, e.r, 0, 2 * Math.PI),
            (o.fillStyle = `rgba(255,255,255,${e.a})`),
            o.fill());
        }),
        a.forEach((e, t) => {
          a.slice(t + 1).forEach((t) => {
            const r = Math.hypot(e.x - t.x, e.y - t.y);
            r < 90 &&
              (o.beginPath(),
              o.moveTo(e.x, e.y),
              o.lineTo(t.x, t.y),
              (o.strokeStyle = `rgba(255,255,255,${0.05 * (1 - r / 90)})`),
              (o.lineWidth = 0.5),
              o.stroke());
          });
        }),
        requestAnimationFrame(e));
    })();
  })());
